fn default_action_object(verb: &str, subject: &str) -> String {
    match verb {
        "list" | "search" => pluralize_phrase(subject),
        "logs" => format!("{subject} logs"),
        "status" => format!("{subject} status"),
        "tail" => format!("{subject} logs"),
        _ => subject.to_owned(),
    }
}

