#[allow(clippy::too_many_arguments)]
fn show_cloudflare_auth_status(
    account: Option<String>,
    environment: Option<String>,
    zone_id: Option<String>,
    zone: Option<String>,
    api_token: Option<String>,
    base_url: Option<String>,
    account_id: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }

    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let runtime = resolve_cloudflare_auth_runtime(
        &settings.cloudflare,
        &env,
        &CloudflareAuthOverrides {
            account: account.unwrap_or_default(),
            environment: environment.unwrap_or_default(),
            zone_id: zone_id.unwrap_or_default(),
            zone_name: zone.unwrap_or_default(),
            base_url: base_url.unwrap_or_default(),
            account_id: account_id.unwrap_or_default(),
            api_token: api_token.unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)?;
    let mut payload = CloudflareAuthStatusPayload::from(&runtime);
    let verify_error = match verify_cloudflare_auth_status(&runtime) {
        Ok(verify) => {
            payload.verify = Some(verify);
            None
        }
        Err(err) => {
            payload.status = "error".to_owned();
            payload.verify_error = Some(err.clone());
            Some(err)
        }
    };

    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            let account = if payload.account_alias.trim().is_empty() {
                "(default)"
            } else {
                payload.account_alias.as_str()
            };
            let zone = if !payload.zone_id.trim().is_empty() {
                payload.zone_id.as_str()
            } else {
                or_dash(&payload.zone_name)
            };
            println!("Cloudflare auth: {}", payload.status);
            println!(
                "Context: account={} ({}) env={} zone={} base={}",
                account,
                or_dash(&payload.account_id),
                payload.environment,
                zone,
                payload.base_url
            );
            println!("Source: {}", or_dash(&payload.source));
            println!("Token preview: {}", or_dash(&payload.token_preview));
        }
    }
    if let Some(err) = verify_error {
        return Err(anyhow::anyhow!(err));
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn show_apple_appstore_auth_status(
    account: Option<String>,
    environment: Option<String>,
    bundle_id: Option<String>,
    locale: Option<String>,
    platform: Option<String>,
    issuer_id: Option<String>,
    key_id: Option<String>,
    private_key: Option<String>,
    private_key_file: Option<String>,
    project_id: Option<String>,
    base_url: Option<String>,
    verify: bool,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }

    let auth_status = resolve_apple_appstore_auth_status(
        &Settings::load(&home.clone().unwrap_or_else(default_home_dir), settings_file.as_deref())?
            .apple,
        &std::env::vars().collect(),
        &AppleAppStoreAuthOverrides {
            account: account.clone().unwrap_or_default(),
            environment: environment.clone().unwrap_or_default(),
            bundle_id: bundle_id.clone().unwrap_or_default(),
            locale: locale.clone().unwrap_or_default(),
            platform: platform.clone().unwrap_or_default(),
            issuer_id: issuer_id.clone().unwrap_or_default(),
            key_id: key_id.clone().unwrap_or_default(),
            private_key: private_key.clone().unwrap_or_default(),
            private_key_file: private_key_file.clone().unwrap_or_default(),
            project_id: project_id.clone().unwrap_or_default(),
            base_url: base_url.clone().unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)?;
    let runtime = load_apple_appstore_runtime(
        account,
        environment,
        bundle_id,
        locale,
        platform,
        issuer_id,
        key_id,
        private_key,
        private_key_file,
        project_id,
        base_url,
        home,
        settings_file,
    )?;
    let mut payload = AppleAppStoreAuthStatusPayload::from(auth_status);
    let issued = issue_apple_appstore_token(&runtime);
    let mut token_error = None;
    if let Ok(token) = &issued {
        if let Some(expires_at) = Utc.timestamp_opt(token.expires_at_epoch as i64, 0).single() {
            payload.token_expires_at = Some(expires_at.to_rfc3339());
        }
    } else if let Err(err) = &issued {
        payload.status = "error".to_owned();
        payload.token_error = Some(err.clone());
        token_error = Some(err.clone());
    }
    let mut verify_error = None;
    if verify && token_error.is_none() {
        let response = run_apple_appstore_api_request(
            &runtime,
            "GET",
            "/v1/apps",
            &BTreeMap::from([("limit".to_owned(), "1".to_owned())]),
            None,
            None,
            None,
        );
        match response {
            Ok(response) => {
                let items = response
                    .data
                    .as_ref()
                    .and_then(|data| data.get("data"))
                    .and_then(Value::as_array)
                    .map(Vec::len)
                    .unwrap_or(0);
                payload.verify = Some(serde_json::json!({
                    "ok": true,
                    "status_code": response.status_code,
                    "items": items,
                }));
            }
            Err(err) => {
                payload.verify_error = Some(err.clone());
                verify_error = Some(err);
            }
        }
    }
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            let account = if payload.account_alias.trim().is_empty() {
                "(default)"
            } else {
                payload.account_alias.as_str()
            };
            println!("Apple App Store auth: {}", payload.status);
            println!(
                "Context: account={} ({}) env={} bundle={} platform={}",
                account,
                or_dash(&payload.project_id),
                payload.environment,
                or_dash(&payload.bundle_id),
                payload.platform
            );
            println!("Source: {}", or_dash(&payload.source));
            println!("Token source: {}", or_dash(&payload.token_source));
            if let Some(expires_at) = &payload.token_expires_at {
                println!("Token expires: {}", expires_at);
            }
            if let Some(err) = &payload.verify_error {
                println!("Verify: {}", err);
            } else if payload.verify.is_some() {
                println!("Verify: ok");
            }
        }
    }
    if let Some(err) = token_error {
        return Err(anyhow::anyhow!(err));
    }
    if let Some(err) = verify_error {
        return Err(anyhow::anyhow!(err));
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn show_apple_appstore_doctor(
    account: Option<String>,
    environment: Option<String>,
    bundle_id: Option<String>,
    locale: Option<String>,
    platform: Option<String>,
    issuer_id: Option<String>,
    key_id: Option<String>,
    private_key: Option<String>,
    private_key_file: Option<String>,
    project_id: Option<String>,
    base_url: Option<String>,
    public: bool,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    if public {
        let probe_url = std::env::var("SI_RUST_APPLE_APPSTORE_PUBLIC_PROBE_URL")
            .unwrap_or_else(|_| "https://developer.apple.com/sample-code/app-store-connect/app-store-connect-openapi-specification.zip".to_owned());
        let response = BlockingHttpClient::builder()
            .timeout(std::time::Duration::from_secs(20))
            .build()
            .context("build apple appstore public probe client")?
            .get(probe_url.trim())
            .send()
            .with_context(|| format!("run apple appstore public probe {}", probe_url.trim()))?;
        let ok = response.status().is_success();
        let payload = serde_json::json!({
            "ok": ok,
            "probe": probe_url.trim(),
            "status_code": response.status().as_u16(),
            "status": response.status().to_string(),
        });
        match format {
            OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
            OutputFormat::Text => {
                if !ok {
                    anyhow::bail!("apple appstore public probe failed: {}", response.status());
                }
                println!("apple appstore public probe ok");
                println!("Probe: {}", probe_url.trim());
            }
        }
        if !ok {
            anyhow::bail!("apple appstore public probe failed: {}", response.status());
        }
        return Ok(());
    }
    show_apple_appstore_auth_status(
        account,
        environment,
        bundle_id,
        locale,
        platform,
        issuer_id,
        key_id,
        private_key,
        private_key_file,
        project_id,
        base_url,
        true,
        home,
        settings_file,
        format,
    )
}

