fn show_aws_context_current(
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }

    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let payload = AWSCurrentContextPayload::from(
        resolve_aws_current_context(&settings.aws, &env).map_err(anyhow::Error::msg)?,
    );
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            let account = if payload.account_alias.trim().is_empty() {
                "(default)"
            } else {
                payload.account_alias.as_str()
            };
            println!(
                "Current aws context: account={} region={} base={}",
                account, payload.region, payload.base_url
            );
            println!("Source: {}", or_dash(&payload.source));
        }
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn show_aws_auth_status(
    account: Option<String>,
    region: Option<String>,
    base_url: Option<String>,
    access_key: Option<String>,
    secret_key: Option<String>,
    session_token: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    let payload = execute_aws_request(
        account,
        region,
        base_url,
        access_key,
        secret_key,
        session_token,
        home,
        settings_file,
        |runtime| Ok::<AWSAuthStatus, String>(verify_aws_auth_status(&runtime)),
    )?;
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            fn or_dash(value: &str) -> &str {
                if value.trim().is_empty() { "-" } else { value }
            }
            let account = if payload.account_alias.trim().is_empty() {
                "(default)"
            } else {
                payload.account_alias.as_str()
            };
            println!("AWS auth: {}", payload.status);
            println!(
                "Context: account={} region={} base={}",
                account, payload.region, payload.base_url
            );
            println!("Source: {}", or_dash(&payload.source));
            println!("Access key: {}", or_dash(&payload.access_key));
        }
    }
    if payload.status != "ready" {
        anyhow::bail!(
            "{}",
            payload.verify_error.unwrap_or_else(|| "aws auth verification failed".to_owned())
        );
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn execute_aws_request<T, F>(
    account: Option<String>,
    region: Option<String>,
    base_url: Option<String>,
    access_key: Option<String>,
    secret_key: Option<String>,
    session_token: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    request: F,
) -> Result<T>
where
    F: FnOnce(AWSRuntimeContext) -> std::result::Result<T, String>,
{
    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let runtime = resolve_aws_runtime(
        &settings.aws,
        &env,
        &AWSAuthOverrides {
            account: account.unwrap_or_default(),
            region: region.unwrap_or_default(),
            base_url: base_url.unwrap_or_default(),
            access_key: access_key.unwrap_or_default(),
            secret_key: secret_key.unwrap_or_default(),
            session_token: session_token.unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)?;
    request(runtime).map_err(anyhow::Error::msg)
}

fn aws_default_service_endpoint(service: &str, region: &str) -> String {
    let service = service.trim().to_ascii_lowercase();
    let region = if region.trim().is_empty() { "us-east-1" } else { region.trim() };
    match service.as_str() {
        "iam" => "https://iam.amazonaws.com".to_owned(),
        "sts" => {
            if region == "us-east-1" {
                "https://sts.amazonaws.com".to_owned()
            } else {
                format!("https://sts.{region}.amazonaws.com")
            }
        }
        "s3" => {
            if region == "us-east-1" {
                "https://s3.amazonaws.com".to_owned()
            } else {
                format!("https://s3.{region}.amazonaws.com")
            }
        }
        "ec2" => format!("https://ec2.{region}.amazonaws.com"),
        "lambda" => format!("https://lambda.{region}.amazonaws.com"),
        "ecr" => format!("https://api.ecr.{region}.amazonaws.com"),
        _ => format!("https://{service}.{region}.amazonaws.com"),
    }
}

#[allow(clippy::too_many_arguments)]
fn execute_aws_service_request<T, F>(
    service: &str,
    account: Option<String>,
    region: Option<String>,
    base_url: Option<String>,
    access_key: Option<String>,
    secret_key: Option<String>,
    session_token: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    request: F,
) -> Result<T>
where
    F: FnOnce(AWSRuntimeContext) -> std::result::Result<T, String>,
{
    let explicit_base_url = base_url.clone();
    execute_aws_request(
        account,
        region,
        base_url,
        access_key,
        secret_key,
        session_token,
        home,
        settings_file,
        |mut runtime| {
            if explicit_base_url.as_deref().unwrap_or_default().trim().is_empty() {
                runtime.base_url = aws_default_service_endpoint(service, &runtime.region);
            }
            request(runtime)
        },
    )
}

fn aws_query_body(action: &str, version: &str, params: &BTreeMap<String, String>) -> String {
    let mut encoded = BTreeMap::new();
    encoded.insert("Action".to_owned(), action.trim().to_owned());
    encoded.insert("Version".to_owned(), version.trim().to_owned());
    for (key, value) in params {
        if key.trim().is_empty() {
            continue;
        }
        encoded.insert(key.trim().to_owned(), value.trim().to_owned());
    }
    url::form_urlencoded::Serializer::new(String::new())
        .extend_pairs(encoded.iter().map(|(k, v)| (k.as_str(), v.as_str())))
        .finish()
}

fn execute_aws_query(
    runtime: &AWSRuntimeContext,
    service: &str,
    version: &str,
    action: &str,
    params: &BTreeMap<String, String>,
) -> std::result::Result<AWSAPIResponse, String> {
    execute_aws_api_request(
        runtime,
        &AWSAPIRequest {
            method: "POST".to_owned(),
            path: "/".to_owned(),
            service: service.to_owned(),
            body: aws_query_body(action, version, params),
            ..AWSAPIRequest::default()
        },
    )
}

fn execute_aws_rest(
    runtime: &AWSRuntimeContext,
    service: &str,
    method: &str,
    path: &str,
    params: &BTreeMap<String, String>,
    body: &str,
    content_type: &str,
) -> std::result::Result<AWSAPIResponse, String> {
    execute_aws_api_request(
        runtime,
        &AWSAPIRequest {
            method: method.to_owned(),
            path: path.to_owned(),
            service: service.to_owned(),
            params: params.clone(),
            body: body.to_owned(),
            content_type: content_type.to_owned(),
            ..AWSAPIRequest::default()
        },
    )
}

fn execute_aws_json(
    runtime: &AWSRuntimeContext,
    service: &str,
    target: &str,
    payload: &Value,
) -> std::result::Result<AWSAPIResponse, String> {
    let mut headers = BTreeMap::new();
    if !target.trim().is_empty() {
        headers.insert("x-amz-target".to_owned(), target.trim().to_owned());
    }
    execute_aws_api_request(
        runtime,
        &AWSAPIRequest {
            method: "POST".to_owned(),
            path: "/".to_owned(),
            service: service.to_owned(),
            headers,
            body: payload.to_string(),
            content_type: "application/x-amz-json-1.1".to_owned(),
            accept: "application/x-amz-json-1.1".to_owned(),
            ..AWSAPIRequest::default()
        },
    )
}

fn aws_s3_object_path(bucket: &str, key: &str) -> String {
    format!("/{}/{}", bucket.trim(), key.trim_start_matches('/'))
}

fn parse_json_value(label: &str, input: &str) -> Result<Value> {
    serde_json::from_str(input).map_err(|err| anyhow::anyhow!("invalid {} json: {}", label, err))
}

fn aws_path_escape(value: &str) -> String {
    url::form_urlencoded::byte_serialize(value.as_bytes()).collect()
}

fn resolve_aws_json_body(
    body: Option<String>,
    body_file: Option<PathBuf>,
    fallback: Option<Value>,
) -> Result<String> {
    if let Some(body) = body.filter(|value| !value.trim().is_empty()) {
        return Ok(body);
    }
    if let Some(path) = body_file {
        let contents = std::fs::read_to_string(path)?;
        if !contents.trim().is_empty() {
            return Ok(contents);
        }
    }
    if let Some(fallback) = fallback {
        return Ok(serde_json::to_string(&fallback)?);
    }
    anyhow::bail!("provide --prompt, --body, or --body-file")
}

fn resolve_aws_json_body_if_present(
    body: Option<String>,
    body_file: Option<PathBuf>,
) -> Result<Option<String>> {
    if let Some(body) = body.filter(|value| !value.trim().is_empty()) {
        return Ok(Some(body));
    }
    if let Some(path) = body_file {
        let contents = std::fs::read_to_string(path)?;
        if !contents.trim().is_empty() {
            return Ok(Some(contents));
        }
    }
    Ok(None)
}

fn parse_aws_key_value_pairs(
    params: Vec<String>,
    flag_name: &str,
) -> Result<BTreeMap<String, String>> {
    let mut parsed = BTreeMap::new();
    for raw in params {
        let (key, value) = raw.split_once('=').ok_or_else(|| {
            anyhow::Error::msg(format!("invalid --{flag_name}: expected key=value"))
        })?;
        if key.trim().is_empty() {
            return Err(anyhow::Error::msg(format!("invalid --{flag_name}: expected key=value")));
        }
        parsed.insert(key.trim().to_owned(), value.to_owned());
    }
    Ok(parsed)
}

fn print_aws_api_response(
    response: &AWSAPIResponse,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(response)?),
        OutputFormat::Text => {
            fn or_dash(value: &str) -> &str {
                if value.trim().is_empty() { "-" } else { value }
            }
            if raw {
                println!("{}", response.body);
                return Ok(());
            }
            println!("Status: {} {}", response.status_code, or_dash(&response.status));
            if !response.request_id.trim().is_empty() {
                println!("Request ID: {}", response.request_id);
            }
            if response.data != Value::Null {
                println!("{}", serde_json::to_string_pretty(&response.data)?);
            } else if !response.body.trim().is_empty() {
                println!("{}", response.body);
            }
        }
    }
    Ok(())
}

