#[allow(clippy::too_many_arguments)]
fn run_aws_iam_query(
    action: String,
    params: Vec<String>,
    account: Option<String>,
    region: Option<String>,
    base_url: Option<String>,
    access_key: Option<String>,
    secret_key: Option<String>,
    session_token: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    let params = params
        .into_iter()
        .filter_map(|entry| {
            let (key, value) = entry.split_once('=')?;
            let key = key.trim().to_owned();
            if key.is_empty() { None } else { Some((key, value.trim().to_owned())) }
        })
        .collect::<BTreeMap<_, _>>();
    let response = execute_aws_service_request(
        "iam",
        account,
        region,
        base_url,
        access_key,
        secret_key,
        session_token,
        home,
        settings_file,
        |runtime| execute_aws_query(&runtime, "iam", "2010-05-08", &action, &params),
    )?;
    print_aws_api_response(&response, format, raw)
}

