#[allow(clippy::too_many_arguments)]
fn show_google_play_auth_status(
    account: Option<String>,
    environment: Option<String>,
    package_name: Option<String>,
    language: Option<String>,
    project_id: Option<String>,
    developer_account: Option<String>,
    service_account_json: Option<String>,
    service_account_file: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    custom_app_base_url: Option<String>,
    verify_package: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }
    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let mut payload = resolve_play_auth_status(
        &settings.google,
        &env,
        &GooglePlayOverrides {
            account: account.clone().unwrap_or_default(),
            environment: environment.clone().unwrap_or_default(),
            package_name: package_name.clone().unwrap_or_default(),
            language: language.clone().unwrap_or_default(),
            project_id: project_id.clone().unwrap_or_default(),
            developer_account: developer_account.clone().unwrap_or_default(),
            service_account_json: service_account_json.clone().unwrap_or_default(),
            service_account_file: service_account_file.clone().unwrap_or_default(),
            base_url: base_url.clone().unwrap_or_default(),
            upload_base_url: upload_base_url.clone().unwrap_or_default(),
            custom_app_base_url: custom_app_base_url.clone().unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)?;
    let runtime = load_google_play_runtime(
        account,
        environment,
        package_name.clone(),
        language,
        project_id,
        developer_account,
        service_account_json,
        service_account_file,
        base_url,
        upload_base_url,
        custom_app_base_url,
        Some(home),
        settings_file,
    )?;
    let mut verify_payload = Value::Null;
    let mut verify_error = String::new();
    let pkg = verify_package
        .filter(|value| !value.trim().is_empty())
        .or_else(|| package_name.filter(|value| !value.trim().is_empty()))
        .or_else(|| {
            if runtime.default_package_name.trim().is_empty() {
                None
            } else {
                Some(runtime.default_package_name.clone())
            }
        });
    if let Some(pkg) = pkg {
        match verify_google_play_package_access(&runtime, &pkg) {
            Ok(_) => verify_payload = serde_json::json!({"package": pkg, "ok": true}),
            Err(err) => {
                verify_payload = serde_json::json!({"package": pkg, "ok": false});
                verify_error = err;
            }
        }
    }
    match format {
        OutputFormat::Json => {
            let mut value = serde_json::to_value(&payload)?;
            if !verify_payload.is_null() {
                value["verify"] = verify_payload;
            }
            if !verify_error.trim().is_empty() {
                value["verify_error"] = Value::String(verify_error);
            }
            println!("{}", serde_json::to_string_pretty(&value)?);
        }
        OutputFormat::Text => {
            println!("Google Play auth: {}", payload.status);
            println!(
                "Context: account={} env={} project={} package={}",
                if payload.account_alias.trim().is_empty() {
                    "(default)"
                } else {
                    payload.account_alias.as_str()
                },
                payload.environment,
                or_dash(&payload.project_id),
                or_dash(&payload.default_package_name)
            );
            println!("Service account: {}", or_dash(&payload.service_account_email));
            println!("Token source: {}", or_dash(&payload.token_source));
            if !payload.token_expires_at.trim().is_empty() {
                println!("Token expires: {}", payload.token_expires_at);
            }
            if !verify_payload.is_null() {
                if verify_error.trim().is_empty() {
                    println!("Package verify: ok");
                } else {
                    println!("Package verify: {}", verify_error);
                }
            }
        }
    }
    let _ = &mut payload;
    Ok(())
}

fn parse_google_play_params(params: Vec<String>) -> Result<BTreeMap<String, String>> {
    let mut out = BTreeMap::new();
    for raw in params {
        let Some((key, value)) = raw.split_once('=') else {
            anyhow::bail!("invalid --param {raw:?} (expected key=value)");
        };
        let key = key.trim();
        if key.is_empty() {
            anyhow::bail!("google play --param key cannot be empty");
        }
        out.insert(key.to_owned(), value.trim().to_owned());
    }
    Ok(out)
}

fn parse_google_play_headers(headers: Vec<String>) -> Result<BTreeMap<String, String>> {
    let mut out = BTreeMap::new();
    for raw in headers {
        let Some((key, value)) = raw.split_once('=') else {
            anyhow::bail!("invalid --header {raw:?} (expected key=value)");
        };
        let key = key.trim();
        if key.is_empty() {
            anyhow::bail!("google play --header key cannot be empty");
        }
        out.insert(key.to_owned(), value.trim().to_owned());
    }
    Ok(out)
}

fn parse_google_play_body(value: Option<String>) -> Result<String> {
    let Some(value) = value else {
        return Ok(String::new());
    };
    let value = value.trim().to_owned();
    if value.is_empty() {
        return Ok(String::new());
    }
    if let Some(path) = value.strip_prefix('@') {
        return Ok(std::fs::read_to_string(path)?.trim().to_owned());
    }
    Ok(value)
}

fn parse_google_play_json_body(value: Option<String>) -> Result<Option<Value>> {
    let body = parse_google_play_body(value)?;
    if body.trim().is_empty() { Ok(None) } else { Ok(Some(serde_json::from_str::<Value>(&body)?)) }
}

fn parse_google_play_version_codes(values: Vec<String>) -> Result<Vec<i64>> {
    let mut out = Vec::new();
    let mut seen = std::collections::BTreeSet::new();
    for raw in values {
        for token in raw.split(',') {
            let token = token.trim();
            if token.is_empty() {
                continue;
            }
            let value = token
                .parse::<i64>()
                .map_err(|_| anyhow::anyhow!("invalid version code {token:?}"))?;
            if value <= 0 {
                anyhow::bail!("invalid version code {token:?}");
            }
            if seen.insert(value) {
                out.push(value);
            }
        }
    }
    out.sort_unstable();
    Ok(out)
}

fn parse_google_play_release_notes(values: Vec<String>) -> Result<Vec<Value>> {
    let mut notes = Vec::new();
    for entry in values {
        let entry = entry.trim();
        if entry.is_empty() {
            continue;
        }
        let Some((language, text)) = entry.split_once('=') else {
            anyhow::bail!("invalid release note {entry:?} (expected <language>=<text>)");
        };
        let language = language.trim();
        let text = text.trim();
        if language.is_empty() || text.is_empty() {
            anyhow::bail!("invalid release note {entry:?} (language and text required)");
        }
        notes.push(serde_json::json!({"language": language, "text": text}));
    }
    Ok(notes)
}

fn normalize_google_play_release_status(raw: &str) -> String {
    match raw.trim().to_ascii_lowercase().as_str() {
        "" | "statusunspecified" | "unspecified" => String::new(),
        "draft" => "draft".to_owned(),
        "inprogress" | "in_progress" | "rollout" | "rolling" => "inProgress".to_owned(),
        "halted" | "paused" => "halted".to_owned(),
        "completed" | "full" | "published" | "production" => "completed".to_owned(),
        _ => String::new(),
    }
}

fn normalize_google_play_image_type(raw: &str) -> String {
    match raw.trim().to_ascii_lowercase().as_str() {
        "phonescreenshots" | "phone" | "phone_screenshots" | "phone-screenshots" => {
            "phoneScreenshots".to_owned()
        }
        "seveninchscreenshots"
        | "7inch"
        | "7-inch"
        | "seven_inch"
        | "seven-inch"
        | "seven_inch_screenshots"
        | "seven-inch-screenshots" => "sevenInchScreenshots".to_owned(),
        "teninchscreenshots"
        | "10inch"
        | "10-inch"
        | "ten_inch"
        | "ten-inch"
        | "ten_inch_screenshots"
        | "ten-inch-screenshots" => "tenInchScreenshots".to_owned(),
        "tvscreenshots" | "tv" | "tv_screenshots" | "tv-screenshots" => "tvScreenshots".to_owned(),
        "wearscreenshots" | "wear" | "wear_screenshots" | "wear-screenshots" => {
            "wearScreenshots".to_owned()
        }
        "icon" | "appicon" | "app_icon" | "app-icon" => "icon".to_owned(),
        "featuregraphic" | "feature_graphic" | "feature-graphic" => "featureGraphic".to_owned(),
        "tvbanner" | "tv_banner" | "tv-banner" => "tvBanner".to_owned(),
        _ => String::new(),
    }
}

fn detect_google_play_media_content_type(path: &str, fallback: &str) -> String {
    let path = path.trim().to_ascii_lowercase();
    if path.ends_with(".png") {
        "image/png".to_owned()
    } else if path.ends_with(".jpg") || path.ends_with(".jpeg") {
        "image/jpeg".to_owned()
    } else if path.ends_with(".webp") {
        "image/webp".to_owned()
    } else if path.ends_with(".apk") {
        "application/vnd.android.package-archive".to_owned()
    } else {
        fallback.to_owned()
    }
}

fn parse_google_play_version_code_value(value: &Value) -> i64 {
    match value {
        Value::Number(number) => number.as_i64().filter(|value| *value > 0).unwrap_or_default(),
        Value::String(text) => {
            text.trim().parse::<i64>().ok().filter(|value| *value > 0).unwrap_or_default()
        }
        _ => 0,
    }
}

fn unique_sorted_google_play_version_codes(values: Vec<i64>) -> Vec<i64> {
    let mut seen = std::collections::BTreeSet::new();
    let mut out = Vec::new();
    for value in values {
        if value > 0 && seen.insert(value) {
            out.push(value);
        }
    }
    out.sort_unstable();
    out
}

fn google_play_version_codes_to_strings(values: &[i64]) -> Vec<String> {
    values.iter().map(|value| value.to_string()).collect()
}

fn extract_google_play_track_version_codes(track: &Value) -> Vec<i64> {
    let Some(releases) = track.get("releases").and_then(Value::as_array) else {
        return Vec::new();
    };
    let mut codes = Vec::new();
    for release in releases {
        let Some(version_codes) = release.get("versionCodes").and_then(Value::as_array) else {
            continue;
        };
        for code in version_codes {
            let parsed = parse_google_play_version_code_value(code);
            if parsed > 0 {
                codes.push(parsed);
            }
        }
    }
    unique_sorted_google_play_version_codes(codes)
}

fn collect_google_play_image_uploads(
    images_root: &Path,
) -> Result<
    Option<std::collections::BTreeMap<String, std::collections::BTreeMap<String, Vec<String>>>>,
> {
    if !images_root.exists() {
        return Ok(None);
    }
    if !images_root.is_dir() {
        anyhow::bail!("images path must be a directory: {}", images_root.display());
    }
    let mut result = std::collections::BTreeMap::new();
    for lang_entry in std::fs::read_dir(images_root)? {
        let lang_entry = lang_entry?;
        if !lang_entry.file_type()?.is_dir() {
            continue;
        }
        let lang = lang_entry.file_name().to_string_lossy().trim().to_owned();
        if lang.is_empty() {
            continue;
        }
        for type_entry in std::fs::read_dir(lang_entry.path())? {
            let type_entry = type_entry?;
            if !type_entry.file_type()?.is_dir() {
                continue;
            }
            let image_type =
                normalize_google_play_image_type(&type_entry.file_name().to_string_lossy());
            if image_type.is_empty() {
                continue;
            }
            let mut files = Vec::new();
            for file in std::fs::read_dir(type_entry.path())? {
                let file = file?;
                if !file.file_type()?.is_file() {
                    continue;
                }
                let path = file.path();
                let lower = path
                    .file_name()
                    .map(|name| name.to_string_lossy().to_ascii_lowercase())
                    .unwrap_or_default();
                if lower.ends_with(".png")
                    || lower.ends_with(".jpg")
                    || lower.ends_with(".jpeg")
                    || lower.ends_with(".webp")
                {
                    files.push(path.display().to_string());
                }
            }
            files.sort();
            if !files.is_empty() {
                result
                    .entry(lang.clone())
                    .or_insert_with(std::collections::BTreeMap::new)
                    .insert(image_type, files);
            }
        }
    }
    if result.is_empty() { Ok(None) } else { Ok(Some(result)) }
}

fn load_google_play_metadata_bundle(
    metadata_dir: &str,
) -> Result<(
    Option<Value>,
    Option<std::collections::BTreeMap<String, Value>>,
    Option<std::collections::BTreeMap<String, std::collections::BTreeMap<String, Vec<String>>>>,
)> {
    let metadata_dir = metadata_dir.trim();
    let metadata_dir = if metadata_dir.is_empty() { "play-store" } else { metadata_dir };
    let metadata_path = PathBuf::from(metadata_dir);
    if !metadata_path.exists() {
        return Ok((None, None, None));
    }
    if !metadata_path.is_dir() {
        anyhow::bail!("metadata dir is not a directory: {}", metadata_path.display());
    }

    let details_path = metadata_path.join("details.json");
    let details = if details_path.exists() {
        Some(serde_json::from_slice::<Value>(&std::fs::read(&details_path)?)?)
    } else {
        None
    };

    let listings_dir = metadata_path.join("listings");
    let mut listings = std::collections::BTreeMap::new();
    if listings_dir.is_dir() {
        for entry in std::fs::read_dir(&listings_dir)? {
            let entry = entry?;
            if !entry.file_type()?.is_file() {
                continue;
            }
            let path = entry.path();
            let lower = path
                .file_name()
                .map(|name| name.to_string_lossy().to_ascii_lowercase())
                .unwrap_or_default();
            if !lower.ends_with(".json") {
                continue;
            }
            let mut payload = serde_json::from_slice::<Value>(&std::fs::read(&path)?)?;
            let language = payload
                .get("language")
                .and_then(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(str::to_owned)
                .or_else(|| path.file_stem().map(|stem| stem.to_string_lossy().trim().to_owned()))
                .filter(|value| !value.is_empty())
                .ok_or_else(|| {
                    anyhow::anyhow!("listing file {} missing language", path.display())
                })?;
            if let Some(object) = payload.as_object_mut() {
                object.remove("language");
            }
            listings.insert(language, payload);
        }
    }

    let images = collect_google_play_image_uploads(&metadata_path.join("images"))?;
    Ok((details, if listings.is_empty() { None } else { Some(listings) }, images))
}

fn resolve_google_play_package(
    runtime: &GooglePlayRuntime,
    package_name: Option<String>,
) -> Result<String> {
    if let Some(value) =
        package_name.map(|value| value.trim().to_owned()).filter(|value| !value.is_empty())
    {
        return Ok(value);
    }
    if !runtime.default_package_name.trim().is_empty() {
        return Ok(runtime.default_package_name.clone());
    }
    anyhow::bail!(
        "package name is required (set --package or configure google.play.accounts.<alias>.default_package_name)"
    )
}

fn resolve_google_play_language(runtime: &GooglePlayRuntime, language: Option<String>) -> String {
    if let Some(value) =
        language.map(|value| value.trim().to_owned()).filter(|value| !value.is_empty())
    {
        return value;
    }
    if !runtime.default_language_code.trim().is_empty() {
        return runtime.default_language_code.clone();
    }
    "en-US".to_owned()
}

fn print_google_play_api_response(
    response: &GooglePlayAPIResponse,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(response)?),
        OutputFormat::Text => {
            println!("Status: {} {}", response.status_code, response.status);
            if !response.request_id.trim().is_empty() {
                println!("Request ID: {}", response.request_id);
            }
            if raw && !response.body.trim().is_empty() {
                println!("{}", response.body);
            } else if let Some(data) = &response.data {
                println!("{}", serde_json::to_string_pretty(data)?);
            } else if !response.body.trim().is_empty() {
                println!("{}", response.body);
            }
        }
    }
    Ok(())
}

fn google_play_run_edit<F>(
    runtime: &GooglePlayRuntime,
    package_name: &str,
    validate: bool,
    changes_not_sent_for_review: bool,
    auto_commit: bool,
    mut operation: F,
) -> Result<GooglePlayAPIResponse>
where
    F: FnMut(&str) -> Result<GooglePlayAPIResponse>,
{
    let insert = execute_play_api_request(
        runtime,
        &GooglePlayAPIRequest {
            method: "POST".to_owned(),
            path: format!(
                "/androidpublisher/v3/applications/{}/edits",
                url::form_urlencoded::byte_serialize(package_name.as_bytes()).collect::<String>()
            ),
            json_body: Some(serde_json::json!({})),
            ..GooglePlayAPIRequest::default()
        },
    )
    .map_err(anyhow::Error::msg)?;
    let edit_id = insert
        .data
        .as_ref()
        .and_then(|value| value.get("id"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| anyhow::anyhow!("edits.insert response missing id"))?
        .to_owned();
    let result = operation(&edit_id);
    if result.is_err() {
        let _ = execute_play_api_request(
            runtime,
            &GooglePlayAPIRequest {
                method: "DELETE".to_owned(),
                path: format!(
                    "/androidpublisher/v3/applications/{}/edits/{}",
                    url::form_urlencoded::byte_serialize(package_name.as_bytes())
                        .collect::<String>(),
                    url::form_urlencoded::byte_serialize(edit_id.as_bytes()).collect::<String>()
                ),
                ..GooglePlayAPIRequest::default()
            },
        );
        return result;
    }
    if !auto_commit {
        let _ = execute_play_api_request(
            runtime,
            &GooglePlayAPIRequest {
                method: "DELETE".to_owned(),
                path: format!(
                    "/androidpublisher/v3/applications/{}/edits/{}",
                    url::form_urlencoded::byte_serialize(package_name.as_bytes())
                        .collect::<String>(),
                    url::form_urlencoded::byte_serialize(edit_id.as_bytes()).collect::<String>()
                ),
                ..GooglePlayAPIRequest::default()
            },
        );
        return result;
    }
    let mut params = BTreeMap::new();
    if changes_not_sent_for_review {
        params.insert("changesNotSentForReview".to_owned(), "true".to_owned());
    }
    let commit = execute_play_api_request(
        runtime,
        &GooglePlayAPIRequest {
            method: "POST".to_owned(),
            path: format!(
                "/androidpublisher/v3/applications/{}/edits/{}{}",
                url::form_urlencoded::byte_serialize(package_name.as_bytes()).collect::<String>(),
                url::form_urlencoded::byte_serialize(edit_id.as_bytes()).collect::<String>(),
                if validate { ":validate" } else { ":commit" }
            ),
            params,
            ..GooglePlayAPIRequest::default()
        },
    )
    .map_err(anyhow::Error::msg)?;
    Ok(commit)
}

fn verify_google_play_package_access(
    runtime: &GooglePlayRuntime,
    package_name: &str,
) -> Result<(), String> {
    google_play_run_edit(runtime, package_name, false, false, false, |_edit_id| {
        Ok(GooglePlayAPIResponse {
            status_code: 200,
            status: "OK".to_owned(),
            request_id: String::new(),
            content_type: "application/json".to_owned(),
            data: None,
            body: String::new(),
        })
    })
    .map(|_| ())
    .map_err(|err| err.to_string())
}

#[allow(clippy::too_many_arguments)]
fn run_google_play_doctor(
    account: Option<String>,
    environment: Option<String>,
    package_name: Option<String>,
    language: Option<String>,
    project_id: Option<String>,
    developer_account: Option<String>,
    service_account_json: Option<String>,
    service_account_file: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    custom_app_base_url: Option<String>,
    verify_package: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    let runtime = load_google_play_runtime(
        account,
        environment,
        package_name.clone(),
        language,
        project_id,
        developer_account,
        service_account_json,
        service_account_file,
        base_url,
        upload_base_url,
        custom_app_base_url,
        home,
        settings_file,
    )?;
    let pkg = verify_package
        .filter(|value| !value.trim().is_empty())
        .or_else(|| package_name.filter(|value| !value.trim().is_empty()))
        .or_else(|| {
            if runtime.default_package_name.trim().is_empty() {
                None
            } else {
                Some(runtime.default_package_name.clone())
            }
        });
    let verify = match pkg {
        Some(pkg) => Some((pkg.clone(), verify_google_play_package_access(&runtime, &pkg))),
        None => None,
    };
    let payload = serde_json::json!({
        "ok": verify.as_ref().map(|(_, result)| result.is_ok()).unwrap_or(true),
        "context": {
            "account_alias": runtime.account_alias,
            "project_id": runtime.project_id,
            "environment": runtime.environment,
            "source": runtime.source,
            "token_source": runtime.token_source,
            "service_account_email": runtime.service_account_email,
            "developer_account_id": runtime.developer_account_id,
            "default_package_name": runtime.default_package_name,
            "default_language_code": runtime.default_language_code,
            "base_url": runtime.base_url,
            "upload_base_url": runtime.upload_base_url,
            "custom_app_base_url": runtime.custom_app_base_url,
        },
        "checks": [
            serde_json::json!({
                "name": "token",
                "ok": true,
                "error": "",
            }),
            serde_json::json!({
                "name": "package.verify",
                "ok": verify.as_ref().map(|(_, result)| result.is_ok()).unwrap_or(true),
                "package": verify.as_ref().map(|(pkg, _)| pkg.clone()).unwrap_or_default(),
                "error": verify.as_ref().and_then(|(_, result)| result.as_ref().err().cloned()).unwrap_or_default(),
            }),
        ],
    });
    match format {
        OutputFormat::Json | OutputFormat::Text => {
            println!("{}", serde_json::to_string_pretty(&payload)?)
        }
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn run_google_play_raw(
    account: Option<String>,
    environment: Option<String>,
    package_name: Option<String>,
    language: Option<String>,
    project_id: Option<String>,
    developer_account: Option<String>,
    service_account_json: Option<String>,
    service_account_file: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    custom_app_base_url: Option<String>,
    method: String,
    path: String,
    params: Vec<String>,
    headers: Vec<String>,
    body: Option<String>,
    json_body: Option<String>,
    content_type: Option<String>,
    media_file: Option<String>,
    upload: bool,
    custom_app: bool,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    let runtime = load_google_play_runtime(
        account,
        environment,
        package_name,
        language,
        project_id,
        developer_account,
        service_account_json,
        service_account_file,
        base_url,
        upload_base_url,
        custom_app_base_url,
        home,
        settings_file,
    )?;
    let json_body = if json_body.as_ref().map(|v| v.trim().is_empty()).unwrap_or(true) {
        None
    } else {
        Some(serde_json::from_str::<Value>(&json_body.unwrap())?)
    };
    let response = execute_play_api_request(
        &runtime,
        &GooglePlayAPIRequest {
            method,
            path,
            params: parse_google_play_params(params)?,
            headers: parse_google_play_headers(headers)?,
            json_body,
            raw_body: parse_google_play_body(body)?,
            media_path: media_file.unwrap_or_default(),
            content_type: content_type.unwrap_or_default(),
            upload,
            custom_app_base: custom_app,
        },
    )
    .map_err(anyhow::Error::msg)?;
    print_google_play_api_response(&response, format, raw)
}

#[allow(clippy::too_many_arguments)]
fn run_google_play_app_create(
    account: Option<String>,
    environment: Option<String>,
    package_name: Option<String>,
    language: Option<String>,
    project_id: Option<String>,
    developer_account: Option<String>,
    service_account_json: Option<String>,
    service_account_file: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    custom_app_base_url: Option<String>,
    title: String,
    organizations: Vec<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    let runtime = load_google_play_runtime(
        account,
        environment,
        package_name,
        language.clone(),
        project_id,
        developer_account,
        service_account_json,
        service_account_file,
        base_url,
        upload_base_url,
        custom_app_base_url,
        home,
        settings_file,
    )?;
    let account_id = if runtime.developer_account_id.trim().is_empty() {
        anyhow::bail!(
            "developer account id is required (set --developer-account or configure google.play.accounts.<alias>.developer_account_id)"
        );
    } else {
        runtime.developer_account_id.clone()
    };
    let lang = resolve_google_play_language(&runtime, language);
    let mut body = serde_json::json!({
        "title": title.trim(),
        "languageCode": lang,
    });
    let orgs: Vec<String> = organizations
        .iter()
        .flat_map(|raw| raw.split(','))
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned)
        .collect();
    if !orgs.is_empty() {
        body["organizations"] = serde_json::json!(orgs);
    }
    let response = execute_play_api_request(
        &runtime,
        &GooglePlayAPIRequest {
            method: "POST".to_owned(),
            path: format!("/playcustomapp/v1/accounts/{}/customApps", account_id),
            json_body: Some(body),
            custom_app_base: true,
            ..GooglePlayAPIRequest::default()
        },
    )
    .map_err(anyhow::Error::msg)?;
    print_google_play_api_response(&response, format, raw)
}

