#[allow(clippy::too_many_arguments)]
fn load_google_youtube_runtime(
    account: Option<String>,
    environment: Option<String>,
    auth_mode: Option<String>,
    api_key: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    project_id: Option<String>,
    language: Option<String>,
    region: Option<String>,
    client_id: Option<String>,
    client_secret: Option<String>,
    redirect_uri: Option<String>,
    access_token: Option<String>,
    refresh_token: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
) -> Result<GoogleYouTubeRuntime> {
    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    resolve_youtube_runtime(
        &settings.google,
        &env,
        &GoogleYouTubeOverrides {
            account: account.unwrap_or_default(),
            environment: environment.unwrap_or_default(),
            auth_mode: auth_mode.unwrap_or_default(),
            api_key: api_key.unwrap_or_default(),
            base_url: base_url.unwrap_or_default(),
            upload_base_url: upload_base_url.unwrap_or_default(),
            project_id: project_id.unwrap_or_default(),
            language: language.unwrap_or_default(),
            region: region.unwrap_or_default(),
            client_id: client_id.unwrap_or_default(),
            client_secret: client_secret.unwrap_or_default(),
            redirect_uri: redirect_uri.unwrap_or_default(),
            access_token: access_token.unwrap_or_default(),
            refresh_token: refresh_token.unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)
}

fn print_google_youtube_api_response(
    response: &GoogleYouTubeAPIResponse,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(response)?),
        OutputFormat::Text => {
            println!("Status: {} {}", response.status_code, response.status);
            if !response.request_id.trim().is_empty() {
                println!("Request ID: {}", response.request_id);
            }
            if raw && !response.body.trim().is_empty() {
                println!("{}", response.body);
            } else if let Some(data) = &response.data {
                println!("{}", serde_json::to_string_pretty(data)?);
            } else if !response.body.trim().is_empty() {
                println!("{}", response.body);
            }
        }
    }
    Ok(())
}

fn parse_google_youtube_params(params: Vec<String>) -> Result<BTreeMap<String, String>> {
    let mut out = BTreeMap::new();
    for raw in params {
        let Some((key, value)) = raw.split_once('=') else {
            anyhow::bail!("invalid --param {raw:?} (expected key=value)");
        };
        let key = key.trim();
        if key.is_empty() {
            anyhow::bail!("google youtube --param key cannot be empty");
        }
        out.insert(key.to_owned(), value.trim().to_owned());
    }
    Ok(out)
}

fn parse_google_youtube_headers(headers: Vec<String>) -> Result<BTreeMap<String, String>> {
    let mut out = BTreeMap::new();
    for raw in headers {
        let Some((key, value)) = raw.split_once('=') else {
            anyhow::bail!("invalid --header {raw:?} (expected key=value)");
        };
        let key = key.trim();
        if key.is_empty() {
            anyhow::bail!("google youtube --header key cannot be empty");
        }
        out.insert(key.to_owned(), value.trim().to_owned());
    }
    Ok(out)
}

fn extract_google_youtube_items(response: &GoogleYouTubeAPIResponse) -> Vec<Value> {
    response
        .data
        .as_ref()
        .and_then(|value| value.get("items"))
        .and_then(Value::as_array)
        .cloned()
        .unwrap_or_default()
}

fn extract_google_youtube_next_page_token(response: &GoogleYouTubeAPIResponse) -> Option<String> {
    response
        .data
        .as_ref()
        .and_then(|value| value.get("nextPageToken"))
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned)
}

fn execute_google_youtube_list_all(
    runtime: &GoogleYouTubeRuntime,
    path: String,
    mut params: BTreeMap<String, String>,
    max_pages: usize,
) -> Result<Value> {
    let mut items = Vec::new();
    let mut next_page_token = String::new();
    for _ in 0..max_pages.max(1) {
        if next_page_token.trim().is_empty() {
            params.remove("pageToken");
        } else {
            params.insert("pageToken".to_owned(), next_page_token.clone());
        }
        let response = execute_youtube_api_request(
            runtime,
            &GoogleYouTubeAPIRequest {
                method: "GET".to_owned(),
                path: path.clone(),
                params: params.clone(),
                ..GoogleYouTubeAPIRequest::default()
            },
        )
        .map_err(anyhow::Error::msg)?;
        items.extend(extract_google_youtube_items(&response));
        next_page_token = extract_google_youtube_next_page_token(&response).unwrap_or_default();
        if next_page_token.is_empty() {
            break;
        }
    }
    Ok(serde_json::json!({
        "count": items.len(),
        "next_page_token": next_page_token,
        "items": items,
    }))
}

fn parse_google_youtube_ids_csv(raw: Option<String>) -> Option<String> {
    let raw = raw?;
    let ids: Vec<String> = raw
        .split(',')
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_owned)
        .collect();
    if ids.is_empty() { None } else { Some(ids.join(",")) }
}

fn parse_google_youtube_body(value: Option<String>) -> Result<String> {
    let Some(value) = value else {
        return Ok(String::new());
    };
    let value = value.trim().to_owned();
    if value.is_empty() {
        return Ok(String::new());
    }
    if let Some(path) = value.strip_prefix('@') {
        return Ok(std::fs::read_to_string(path)?.trim().to_owned());
    }
    Ok(value)
}

fn require_google_youtube_oauth(runtime: &GoogleYouTubeRuntime, operation: &str) -> Result<()> {
    if runtime.auth_mode == "oauth" {
        Ok(())
    } else {
        anyhow::bail!(
            "{} requires oauth mode; run with --mode oauth and login via `si orbit google youtube auth login`",
            operation
        )
    }
}

fn load_google_youtube_runtime_from_command(
    command: GoogleYouTubeMutationRuntimeArgs,
) -> Result<(GoogleYouTubeRuntime, OutputFormat, bool)> {
    let format = if command.json { OutputFormat::Json } else { command.format };
    let raw = command.raw;
    let runtime = load_google_youtube_runtime(
        command.account,
        command.env,
        command.auth_mode,
        command.api_key,
        command.base_url,
        command.upload_base_url,
        command.project_id,
        command.language,
        command.region,
        command.client_id,
        command.client_secret,
        command.redirect_uri,
        command.access_token,
        command.refresh_token,
        command.home,
        command.settings_file,
    )?;
    Ok((runtime, format, raw))
}

fn run_google_youtube_oauth_request(
    command: GoogleYouTubeMutationRuntimeArgs,
    operation: &str,
    method: &str,
    path: &str,
    params: BTreeMap<String, String>,
    body: Option<String>,
) -> Result<()> {
    let (runtime, format, raw) = load_google_youtube_runtime_from_command(command)?;
    require_google_youtube_oauth(&runtime, operation)?;
    let response = execute_youtube_api_request(
        &runtime,
        &GoogleYouTubeAPIRequest {
            method: method.to_owned(),
            path: path.to_owned(),
            params,
            raw_body: body.unwrap_or_default(),
            ..GoogleYouTubeAPIRequest::default()
        },
    )
    .map_err(anyhow::Error::msg)?;
    print_google_youtube_api_response(&response, format, raw)
}

fn verify_google_youtube_auth(runtime: &GoogleYouTubeRuntime) -> Result<(), String> {
    let mut params = BTreeMap::new();
    if runtime.auth_mode == "oauth" {
        params.insert("part".to_owned(), "id".to_owned());
        params.insert("mine".to_owned(), "true".to_owned());
        params.insert("maxResults".to_owned(), "1".to_owned());
        execute_youtube_api_request(
            runtime,
            &GoogleYouTubeAPIRequest {
                method: "GET".to_owned(),
                path: "/youtube/v3/channels".to_owned(),
                params,
                ..GoogleYouTubeAPIRequest::default()
            },
        )?;
    } else {
        params.insert("part".to_owned(), "id".to_owned());
        params.insert("maxResults".to_owned(), "1".to_owned());
        params.insert("type".to_owned(), "video".to_owned());
        params.insert("q".to_owned(), "music".to_owned());
        execute_youtube_api_request(
            runtime,
            &GoogleYouTubeAPIRequest {
                method: "GET".to_owned(),
                path: "/youtube/v3/search".to_owned(),
                params,
                ..GoogleYouTubeAPIRequest::default()
            },
        )?;
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn run_google_youtube_channel_list(
    account: Option<String>,
    environment: Option<String>,
    auth_mode: Option<String>,
    api_key: Option<String>,
    base_url: Option<String>,
    upload_base_url: Option<String>,
    project_id: Option<String>,
    language: Option<String>,
    region: Option<String>,
    client_id: Option<String>,
    client_secret: Option<String>,
    redirect_uri: Option<String>,
    access_token: Option<String>,
    refresh_token: Option<String>,
    part: String,
    ids: Option<String>,
    for_handle: Option<String>,
    for_username: Option<String>,
    mine: bool,
    max_results: Option<usize>,
    page_token: Option<String>,
    params: Vec<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
    raw: bool,
) -> Result<()> {
    let runtime = load_google_youtube_runtime(
        account,
        environment,
        auth_mode,
        api_key,
        base_url,
        upload_base_url,
        project_id,
        language,
        region,
        client_id,
        client_secret,
        redirect_uri,
        access_token,
        refresh_token,
        home,
        settings_file,
    )?;
    if mine {
        require_google_youtube_oauth(&runtime, "channel list --mine")?;
    }
    let mut params = parse_google_youtube_params(params)?;
    params.insert("part".to_owned(), part.trim().to_owned());
    if let Some(ids) = parse_google_youtube_ids_csv(ids) {
        params.insert("id".to_owned(), ids);
    }
    if let Some(for_handle) = for_handle.map(|v| v.trim().to_owned()).filter(|v| !v.is_empty()) {
        params.insert("forHandle".to_owned(), for_handle);
    }
    if let Some(for_username) = for_username.map(|v| v.trim().to_owned()).filter(|v| !v.is_empty())
    {
        params.insert("forUsername".to_owned(), for_username);
    }
    if mine {
        params.insert("mine".to_owned(), "true".to_owned());
    }
    params.insert("maxResults".to_owned(), max_results.unwrap_or(10).clamp(1, 50).to_string());
    if let Some(page_token) = page_token.map(|v| v.trim().to_owned()).filter(|v| !v.is_empty()) {
        params.insert("pageToken".to_owned(), page_token);
    }
    let response = execute_youtube_api_request(
        &runtime,
        &GoogleYouTubeAPIRequest {
            method: "GET".to_owned(),
            path: "/youtube/v3/channels".to_owned(),
            params,
            ..GoogleYouTubeAPIRequest::default()
        },
    )
    .map_err(anyhow::Error::msg)?;
    print_google_youtube_api_response(&response, format, raw)
}

