#[allow(clippy::too_many_arguments)]
fn run_openai_doctor(
    account: Option<String>,
    base_url: Option<String>,
    api_key: Option<String>,
    admin_api_key: Option<String>,
    org_id: Option<String>,
    project_id: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }

    let (runtime, checks) = execute_openai_request(
        account,
        base_url,
        api_key,
        admin_api_key,
        org_id,
        project_id,
        home,
        settings_file,
        |runtime| {
            let verify = openai_list_models(&runtime, Some(1));
            let request_detail = match &verify {
                Ok(response) => format!("{} {}", response.status_code, response.status),
                Err(err) => err.clone(),
            };
            let checks = vec![
                DoctorCheckPayload {
                    name: "api-key".to_owned(),
                    ok: !runtime.api_key.trim().is_empty(),
                    detail: preview_secret(&runtime.api_key),
                },
                DoctorCheckPayload {
                    name: "base-url".to_owned(),
                    ok: !runtime.base_url.trim().is_empty(),
                    detail: runtime.base_url.clone(),
                },
                DoctorCheckPayload {
                    name: "request".to_owned(),
                    ok: verify.is_ok(),
                    detail: request_detail,
                },
            ];
            Ok::<(OpenAIRuntime, Vec<DoctorCheckPayload>), String>((runtime, checks))
        },
    )?;
    let ok = checks.iter().all(|check| check.ok);
    let payload = serde_json::json!({
        "ok": ok,
        "provider": "openai",
        "base_url": runtime.base_url.clone(),
        "account_alias": runtime.account_alias.clone(),
        "organization_id": runtime.organization_id.clone(),
        "project_id": runtime.project_id.clone(),
        "checks": checks,
    });

    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            let account = if runtime.account_alias.trim().is_empty() {
                "(default)"
            } else {
                runtime.account_alias.as_str()
            };
            println!("OpenAI doctor: {}", if ok { "ok" } else { "issues found" });
            println!(
                "Context: account={} base={} org={} project={}",
                account,
                runtime.base_url,
                or_dash(&runtime.organization_id),
                or_dash(&runtime.project_id)
            );
            for check in &checks {
                println!(
                    "  {}  {}  {}",
                    if check.ok { "OK" } else { "ERR" },
                    check.name,
                    or_dash(&check.detail)
                );
            }
        }
    }

    if !ok {
        anyhow::bail!("openai doctor failed");
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn show_openai_context_current(
    account: Option<String>,
    base_url: Option<String>,
    api_key: Option<String>,
    admin_api_key: Option<String>,
    org_id: Option<String>,
    project_id: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    format: OutputFormat,
) -> Result<()> {
    fn or_dash(value: &str) -> &str {
        if value.trim().is_empty() { "-" } else { value }
    }

    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let payload = OpenAICurrentContextPayload::from(
        resolve_openai_current_context(
            &settings.openai,
            &env,
            &OpenAIContextOverrides {
                account: account.unwrap_or_default(),
                base_url: base_url.unwrap_or_default(),
                api_key: api_key.unwrap_or_default(),
                admin_api_key: admin_api_key.unwrap_or_default(),
                org_id: org_id.unwrap_or_default(),
                project_id: project_id.unwrap_or_default(),
            },
        )
        .map_err(anyhow::Error::msg)?,
    );
    match format {
        OutputFormat::Json => println!("{}", serde_json::to_string_pretty(&payload)?),
        OutputFormat::Text => {
            let account = if payload.account_alias.trim().is_empty() {
                "(default)"
            } else {
                payload.account_alias.as_str()
            };
            println!(
                "Current openai context: account={} base={} org={} project={}",
                account,
                payload.base_url,
                or_dash(&payload.organization_id),
                or_dash(&payload.project_id)
            );
            println!("Source: {}", or_dash(&payload.source));
            println!("Admin key set: {}", if payload.admin_key_set { "true" } else { "false" });
        }
    }
    Ok(())
}

