#[allow(clippy::too_many_arguments)]
fn run_stripe_sync_plan(
    account: Option<String>,
    live_api_key: Option<String>,
    sandbox_api_key: Option<String>,
    base_url: Option<String>,
    only: Vec<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    json: bool,
) -> Result<()> {
    let (plan, live_runtime, sandbox_runtime) = build_stripe_sync_plan(
        account,
        live_api_key,
        sandbox_api_key,
        base_url,
        only,
        home,
        settings_file,
    )?;
    if json {
        println!("{}", serde_json::to_string_pretty(&plan)?);
    } else {
        println!(
            "Sync plan: {} action(s) live={} sandbox={}",
            plan.actions.len(),
            live_runtime.account_alias,
            sandbox_runtime.account_alias
        );
        for action in &plan.actions {
            println!(
                "  {} {} live={} sandbox={} {}",
                stripe_sync_family_name(action.family),
                stripe_sync_action_name(action.action),
                if action.live_id.is_empty() { "-" } else { action.live_id.as_str() },
                if action.sandbox_id.is_empty() { "-" } else { action.sandbox_id.as_str() },
                action.reason
            );
        }
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn run_stripe_sync_apply(
    account: Option<String>,
    live_api_key: Option<String>,
    sandbox_api_key: Option<String>,
    base_url: Option<String>,
    only: Vec<String>,
    dry_run: bool,
    force: bool,
    json: bool,
    idempotency_key: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
) -> Result<()> {
    if !force && !dry_run {
        anyhow::bail!("stripe sync apply requires --force");
    }
    let (plan, _live_runtime, sandbox_runtime) = build_stripe_sync_plan(
        account,
        live_api_key,
        sandbox_api_key,
        base_url,
        only,
        home,
        settings_file,
    )?;
    let mut result = StripeSyncApplyResult {
        applied: 0,
        skipped: 0,
        failures: 0,
        errors: Vec::new(),
        mappings: plan.mappings.clone(),
        completed: Vec::new(),
    };
    let idempotency_key = idempotency_key.unwrap_or_default();

    for action in &plan.actions {
        if action.action == StripeSyncActionType::Archive && action.sandbox_id.trim().is_empty() {
            result.skipped += 1;
            continue;
        }
        if dry_run {
            result.skipped += 1;
            result.completed.push(action.clone());
            continue;
        }
        if let Err(err) = apply_stripe_sync_action(
            &sandbox_runtime,
            action,
            &mut result.mappings,
            idempotency_key.trim(),
        ) {
            result.failures += 1;
            result.errors.push(format!(
                "{} {}: {err}",
                stripe_sync_family_name(action.family),
                stripe_sync_action_name(action.action)
            ));
            continue;
        }
        result.applied += 1;
        result.completed.push(action.clone());
    }

    if json {
        println!("{}", serde_json::to_string_pretty(&result)?);
    } else if dry_run {
        println!("dry-run complete: skipped={}", result.skipped);
    } else {
        println!("sync apply complete: applied={} skipped={}", result.applied, result.skipped);
    }

    if result.failures > 0 {
        anyhow::bail!("sync apply completed with {} failure(s)", result.failures);
    }
    Ok(())
}

fn parse_cloudflare_key_values(values: Vec<String>) -> std::collections::BTreeMap<String, String> {
    let mut out = std::collections::BTreeMap::new();
    for entry in values {
        let trimmed = entry.trim();
        if trimmed.is_empty() {
            continue;
        }
        if let Some((key, value)) = trimmed.split_once('=') {
            let key = key.trim();
            if key.is_empty() {
                continue;
            }
            out.insert(key.to_owned(), value.trim().to_owned());
        }
    }
    out
}

#[allow(clippy::too_many_arguments)]
fn execute_cloudflare_request(
    account: Option<String>,
    environment: Option<String>,
    zone_id: Option<String>,
    zone: Option<String>,
    api_token: Option<String>,
    base_url: Option<String>,
    account_id: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    request: CloudflareAPIRequest,
) -> Result<CloudflareAPIResponse> {
    let home = home.unwrap_or_else(default_home_dir);
    let settings = Settings::load(&home, settings_file.as_deref())?;
    let env = std::env::vars().collect();
    let runtime = resolve_cloudflare_auth_runtime(
        &settings.cloudflare,
        &env,
        &CloudflareAuthOverrides {
            account: account.unwrap_or_default(),
            environment: environment.unwrap_or_default(),
            zone_id: zone_id.unwrap_or_default(),
            zone_name: zone.unwrap_or_default(),
            base_url: base_url.unwrap_or_default(),
            account_id: account_id.unwrap_or_default(),
            api_token: api_token.unwrap_or_default(),
        },
    )
    .map_err(anyhow::Error::msg)?;
    let request = CloudflareAPIRequest {
        path: resolve_cloudflare_path_template(&request.path, &runtime)?,
        ..request
    };
    execute_cloudflare_api_request(&runtime, &request).map_err(anyhow::Error::msg)
}

fn resolve_cloudflare_path_template(path: &str, runtime: &CloudflareAuthRuntime) -> Result<String> {
    let mut resolved = path.trim().to_owned();
    if resolved.contains("{account_id}") {
        let account_id = runtime.account_id.trim();
        if account_id.is_empty() {
            anyhow::bail!("account id is required");
        }
        resolved = resolved.replace("{account_id}", account_id);
    }
    if resolved.contains("{zone_id}") {
        let zone_id = runtime.zone_id.trim();
        if zone_id.is_empty() {
            anyhow::bail!("zone id is required");
        }
        resolved = resolved.replace("{zone_id}", zone_id);
    }
    Ok(resolved)
}

fn print_cloudflare_api_response(
    response: &CloudflareAPIResponse,
    json: bool,
    raw: bool,
) -> Result<()> {
    if json {
        println!("{}", serde_json::to_string_pretty(response)?);
    } else {
        print!("{}", render_cloudflare_api_response_text(response, raw));
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn run_cloudflare_raw(
    method: String,
    path: String,
    body: Option<String>,
    json: bool,
    raw: bool,
    params: Vec<String>,
    account: Option<String>,
    environment: Option<String>,
    zone_id: Option<String>,
    zone: Option<String>,
    api_token: Option<String>,
    base_url: Option<String>,
    account_id: Option<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
) -> Result<()> {
    if path.trim().is_empty() {
        anyhow::bail!("path is required");
    }
    let response = execute_cloudflare_request(
        account,
        environment,
        zone_id,
        zone,
        api_token,
        base_url,
        account_id,
        home,
        settings_file,
        CloudflareAPIRequest {
            method,
            path,
            params: parse_cloudflare_key_values(params),
            raw_body: body.unwrap_or_default(),
            ..CloudflareAPIRequest::default()
        },
    )?;
    print_cloudflare_api_response(&response, json, raw)
}

