fn run_cloudflare_resource_command(
    spec: CloudflareResourceSpec,
    command: CloudflareResourceCommand,
) -> Result<()> {
    match command {
        CloudflareResourceCommand::List {
            max_pages,
            limit,
            json,
            raw,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        } => run_cloudflare_resource_list(
            spec,
            max_pages,
            limit,
            json,
            raw,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        ),
        CloudflareResourceCommand::Get {
            id,
            json,
            raw,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        } => run_cloudflare_resource_get(
            spec,
            id,
            json,
            raw,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        ),
        CloudflareResourceCommand::Create {
            json,
            raw,
            body,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        } => run_cloudflare_resource_create(
            spec,
            json,
            raw,
            body,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        ),
        CloudflareResourceCommand::Update {
            id,
            json,
            raw,
            body,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        } => run_cloudflare_resource_update(
            spec,
            id,
            json,
            raw,
            body,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        ),
        CloudflareResourceCommand::Delete {
            id,
            json,
            raw,
            force,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        } => run_cloudflare_resource_delete(
            spec,
            id,
            json,
            raw,
            force,
            params,
            account,
            env,
            zone_id,
            zone,
            api_token,
            base_url,
            account_id,
            home,
            settings_file,
        ),
    }
}

