#[allow(clippy::too_many_arguments)]
fn run_github_release_create(
    repo_ref: Option<String>,
    account: Option<String>,
    owner: Option<String>,
    base_url: Option<String>,
    auth_mode: Option<String>,
    token: Option<String>,
    app_id: Option<i64>,
    app_key: Option<String>,
    installation_id: Option<i64>,
    tag: Option<String>,
    title: Option<String>,
    notes: Option<String>,
    notes_file: Option<PathBuf>,
    target: Option<String>,
    draft: bool,
    prerelease: bool,
    params: Vec<String>,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    json: bool,
    raw: bool,
) -> Result<()> {
    let runtime = load_github_runtime(
        account,
        owner,
        base_url,
        auth_mode,
        token,
        app_id,
        app_key,
        installation_id,
        home,
        settings_file,
    )?;
    let (repo_owner, repo_name) =
        parse_github_owner_repo(repo_ref.as_deref().unwrap_or_default(), &runtime.owner)?;
    let tag = tag
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| anyhow::Error::msg("--tag and --title are required"))?;
    let title = title
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| anyhow::Error::msg("--tag and --title are required"))?;
    let mut payload = parse_github_body_params(params)?;
    payload.insert("tag_name".to_owned(), Value::String(tag.trim().to_owned()));
    payload.insert("name".to_owned(), Value::String(title.trim().to_owned()));
    let notes_text = if let Some(path) = notes_file {
        std::fs::read_to_string(path)?
    } else {
        notes.unwrap_or_default()
    };
    if !notes_text.trim().is_empty() {
        payload.insert("body".to_owned(), Value::String(notes_text));
    }
    let resolved_target =
        target.filter(|value| !value.trim().is_empty()).map(|value| value.trim().to_owned());
    ensure_github_release_tag_exists(
        &runtime,
        &repo_owner,
        &repo_name,
        tag.trim(),
        resolved_target.as_deref(),
    )?;
    if let Some(target) = resolved_target.as_deref() {
        payload.insert("target_commitish".to_owned(), Value::String(target.to_owned()));
    }
    if draft {
        payload.insert("draft".to_owned(), Value::Bool(true));
    }
    if prerelease {
        payload.insert("prerelease".to_owned(), Value::Bool(true));
    }
    let response = github_create_release(&runtime, &repo_owner, &repo_name, Value::Object(payload))
        .map_err(anyhow::Error::msg)?;
    print_github_api_response(&response, json, raw)
}

#[allow(clippy::too_many_arguments)]
fn github_error_status_code(error: &str) -> Option<u16> {
    let marker = "status=";
    let rest = error.split(marker).nth(1)?;
    let digits = rest.chars().take_while(|ch| ch.is_ascii_digit()).collect::<String>();
    if digits.is_empty() {
        return None;
    }
    digits.parse::<u16>().ok()
}

fn ensure_github_release_tag_exists(
    runtime: &GitHubRuntime,
    owner: &str,
    repo: &str,
    tag: &str,
    target: Option<&str>,
) -> Result<()> {
    match github_get_tag_ref(runtime, owner, repo, tag) {
        Ok(_) => Ok(()),
        Err(error) if github_error_status_code(&error) == Some(404) => {
            let target = target.ok_or_else(|| {
                anyhow::Error::msg(format!(
                    "github tag {} does not exist; pass --target <sha> or create the tag first",
                    tag.trim()
                ))
            })?;
            github_create_tag_ref(runtime, owner, repo, tag, target).map_err(anyhow::Error::msg)?;
            Ok(())
        }
        Err(error) => Err(anyhow::Error::msg(error)),
    }
}

#[allow(clippy::too_many_arguments)]
fn run_github_release_upload(
    repo_ref: Option<String>,
    release_ref: Option<String>,
    account: Option<String>,
    owner: Option<String>,
    base_url: Option<String>,
    auth_mode: Option<String>,
    token: Option<String>,
    app_id: Option<i64>,
    app_key: Option<String>,
    installation_id: Option<i64>,
    asset: Option<PathBuf>,
    label: Option<String>,
    content_type: String,
    home: Option<PathBuf>,
    settings_file: Option<PathBuf>,
    json: bool,
    raw: bool,
) -> Result<()> {
    let runtime = load_github_runtime(
        account,
        owner,
        base_url,
        auth_mode,
        token,
        app_id,
        app_key,
        installation_id,
        home,
        settings_file,
    )?;
    let (repo_owner, repo_name) =
        parse_github_owner_repo(repo_ref.as_deref().unwrap_or_default(), &runtime.owner)?;
    let release_ref = release_ref
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| anyhow::Error::msg("release tag or id is required"))?;
    let asset = asset.ok_or_else(|| anyhow::Error::msg("--asset is required"))?;
    let asset_bytes = std::fs::read(&asset)?;
    let asset_name =
        asset.file_name().and_then(|item| item.to_str()).unwrap_or_default().trim().to_owned();
    if asset_name.is_empty() {
        return Err(anyhow::Error::msg("--asset is required"));
    }
    let response = github_upload_release_asset(
        &runtime,
        &repo_owner,
        &repo_name,
        &release_ref,
        &asset_name,
        label.as_deref().unwrap_or_default(),
        &content_type,
        &asset_bytes,
    )
    .map_err(anyhow::Error::msg)?;
    print_github_api_response(&response, json, raw)
}

