fn github_secret_created_response(data: Value) -> GitHubAPIResponse {
    GitHubAPIResponse {
        status_code: 201,
        status: "201 Created".to_owned(),
        request_id: String::new(),
        headers: BTreeMap::new(),
        body: String::new(),
        data: Some(data),
        list: Vec::new(),
    }
}

